INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('AO Tennis 2', '08/01/2020', 'Big Ant Studios', 'co1xwu.webp', 'zQsVFXsf2n0', 'ar7tx.webp', 'Shooter, Platform, Puzzle', 'Abandonado', 2, 5, 32, 'Steam', 125479, 2024, 'Lanzado para coincidir con el Open de Australia, el primer gran torneo de tenis del año, AO Tennis 2 ofrece un nivel de profundidad sin precedentes y una amplia gama de opciones de personalización para una experiencia de juego a medida. En el nuevo modo carrera, podrás dominar la pista, labrarte una reputación, llegar a lo más alto y convertirte en una leyenda del tenis.');
