INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Bright Memory', '24/03/2020', 'FYQD-Studio', 'co26z5.webp', 's73I1DaHnqM', 'ar11k3.webp', 'Shooter, Adventure, Indie', 'Completado', 1, 5, 12, 'Steam', 134072, 2025, 'Bright Memory es una fusión vertiginosa de los géneros FPS y acción, creada por el estudio de desarrollo independiente FYQD utilizando Unreal Engine. Combina una amplia variedad de habilidades y destrezas para desatar deslumbrantes ataques combinados. La aventura de Shelia, agente de la SRO (Organización de Investigación Científica Sobrenatural), está a punto de comenzar.');
