INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Call of Duty® (2003)', '29/10/2003', 'Infinity Ward', 'co2n19.png', 'YUrUDrjOFYY', 'arejd.webp', 'Shooter', 'Completado', 6, 0, 0, 'Steam', 621, 2024, '«Call of Duty» (2003) es el juego inaugural de la aclamada serie de shooters en primera persona desarrollada por Infinity Ward y publicada por Activision. Ambientado en la Segunda Guerra Mundial, ofrece una experiencia intensa y cinematográfica que lleva a los jugadores a través de batallas clave en el Teatro de Operaciones Europeo. El juego incluye tres campañas entrelazadas que permiten a los jugadores luchar como soldados estadounidenses, británicos y soviéticos.');
INSERT INTO dates_played (game_id, year, fecha_inicio, fecha_final, horas) VALUES ((SELECT id FROM games WHERE title = 'Call of Duty® (2003)'), 2024, '10/02/2024', '11/02/2024', 6);
INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Call of Duty® 2', '25/10/2005', 'Infinity Ward', 'co3acf.png', 'XexzQKXGQrk', 'ar798.webp', 'Shooter', 'Completado', 9, 0, 0, 'Steam', 622, 2024, '«Call of Duty 2» es un juego de disparos en primera persona desarrollado por Infinity Ward y publicado por Activision, que constituye la aclamada secuela del "Call of Duty" original. Lanzado en 2005, el juego sumerge a los jugadores en las apasionantes y caóticas batallas de la Segunda Guerra Mundial en varios teatros de guerra.');
