INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Call of Duty® 4: Modern Warfare® (2007)', '05/11/2007', 'Treyarch', 'co1wko.png', '8e-i2D-2GAc', 'ar79g.webp', 'Shooter, Simulator', 'Completado', 6, 0, 0, 'Steam', 623, 2024, 'Call of Duty 4: Modern Warfare difiere de las anteriores entregas de la serie Call of Duty. Los anteriores juegos de Call of Duty tenían un estilo de campaña específico para tres países, mientras que Call of Duty 4 tiene una trama más cinematográfica, con historias entrelazadas desde las perspectivas del sargento Paul Jackson, de la 1st Force Recon de los Marines, y del sargento ''Soap'' MacTavish, del 22º Regimiento SAS británico.');
