INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Call of Duty: World at War', '10/11/2008', 'Treyarch', 'co1wl8.webp', 'PLT2AmsdGNg', 'ar7j1.webp', 'Shooter, Adventure', 'Completado', 8, 0, 0, 'Steam', 625, 2024, 'Call of Duty: World at War sumerge a los jugadores en los combates más cruentos y caóticos de la Segunda Guerra Mundial. Los jugadores se unen para sobrevivir a las batallas más angustiantes y culminantes que llevaron a la desaparición de las potencias del Eje en los frentes de Europa y el Pacífico.');
