INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('DmC: Devil May Cry', '14/01/2013', 'Ninja Theory', 'co1u77.webp', 'jccTX6Q-s28', 'ar5jbw.png', 'Puzzle, Hack and slash/Beat ''em up, Adventure', 'Completado', 8, 22, 58, 'Steam', 1254, 2026, 'DmC: Devil May Cry es el quinto juego de la serie de acción en tercera persona hack-and-slash y el primero que no ha sido desarrollado en su mayor parte por Capcom. Este título es una reinvención de la serie, con el mismo protagonista, Dante, pero ambientado en un universo alternativo. El Dante de este juego es muy diferente al anterior, ya que se ha eliminado su característico cabello blanco y se ha modificado tanto el personaje principal como el tono del juego, con una influencia mucho más occidental. La jugabilidad sigue siendo prácticamente idéntica, ya que Dante se enfrenta a muchos oponentes con un estilo de lucha rápido, encadenando combos y golpes en rápida sucesión.');
