INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Enshrouded', '24/01/2024', 'Keen Games', 'co6gct.png', 'A2Pdio9EqRU', 'ar2bav.webp', 'Role-playing (RPG), Adventure', 'Completado', 120, 33, 37, 'Steam', 248643, 2024, 'Eres Flameborn, el último rescoldo de esperanza de una raza moribunda. Despierta, sobrevive al terror de una niebla corruptora y recupera la belleza perdida de tu reino. Aventúrate en un vasto mundo, derrota a los jefes, construye grandes salones y forja tu camino en este RPG de acción y supervivencia cooperativo para hasta 16 jugadores.');
