INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('The Gunk', '15/12/2021', 'Image & Form', 'co49u0.webp', 'Cs96h12uHiE', 'ar19wj.webp', 'Adventure', 'Completado', 5, 16, 17, 'Xbox Series X', 136000, 2025, 'The Gunk es un juego de aventuras protagonizado por Rani, uno de los miembros de nuestro dúo de valientes transportistas espaciales, que luchan por ganarse la vida cuando se topan con un planeta virgen rebosante de vida. Vinieron en busca de recursos valiosos y parece que han dado con el premio gordo...');
INSERT INTO dates_played (game_id, year, fecha_inicio, fecha_final, horas) VALUES ((SELECT id FROM games WHERE title = 'The Gunk'), 2025, '21/09/2025', '22/09/2025', 5);
INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('The Incredible Adventures of Van Helsing', '21/05/2013', 'NeocoreGames', 'co23cq.webp', 'ulfLPCF2yR4', 'crivtxumvix0zqwhvqsh.webp', 'Role-playing (RPG), Strategy, Hack and slash/Beat ''em up, Adventure, Indie', 'Completado', 11, 54, 95, 'Steam', 2638, 2025, 'Ponte tu sombrero de ala ancha, coge tus armas y embárcate en una increíble aventura en el mundo gótico-noir de Borgovia, donde la ciencia loca amenaza la frágil paz entre monstruos y mortales.');
