INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Wheel World', '22/07/2025', 'Messhof', 'co8ycw.webp', '6Jx-PeNzly', 'ar3voj.webp', 'Racing, Sport, Adventure', 'Completado', 11, 25, 41, 'Xbox Series X', 255091, 2025, 'Sumérgete en Wheel World como Kat, una ciclista elegida por antiguos espíritus ciclistas. Compite contra equipos de élite, tunea tu bicicleta y realiza el esperado ritual del Gran Cambio para salvar un universo al borde del abismo. Tu bicicleta es tu destino.');
INSERT INTO dates_played (game_id, year, fecha_inicio, fecha_final, horas) VALUES ((SELECT id FROM games WHERE title = 'Wheel World'), 2025, '25/07/2025', '27/07/2025', 11);
INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Windrose', '', 'Windrose Crew', 'coay9m.webp', 'EDnFI1SLMLo', 'ar4uzq.webp', 'Role-playing (RPG), Adventure', 'Completado', 4, 0, 0, 'Steam', 380441, 2026, 'Windrose es una aventura de supervivencia ambientada en la era de la piratería. Explora un mundo abierto procedural, recolecta, construye y crea objetos. Derrota a jefes desafiantes en combates al estilo Souls. Navega con tu barco, lucha en tierra y mar, juega solo o con amigos.');
INSERT INTO dates_played (game_id, year, fecha_inicio, fecha_final, horas) VALUES ((SELECT id FROM games WHERE title = 'Windrose'), 2026, '22/02/2026', '22/02/2026', 4);
INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('World of Goo', '03/04/2013', '2D Boy', 'co24jz.webp', '92rWWaspoFI', 'arcrb.webp', 'Puzzle, Simulator, Strategy, Indie', 'Completado', 7, 1, 8, 'Steam', 942, 2025, 'World of Goo es un juego de construcción y rompecabezas basado en la física, ganador de múltiples premios, creado íntegramente por dos personas. Arrastra y suelta bolas de sustancia viscosa vivientes, retorcidas y parlantes para construir estructuras, puentes, balas de cañón, zepelines y lenguas gigantes.');
INSERT INTO dates_played (game_id, year, fecha_inicio, fecha_final, horas) VALUES ((SELECT id FROM games WHERE title = 'World of Goo'), 2025, '29/09/2025', '26/10/2025', 7);
INSERT INTO games (title, released, companie, poster, trailer, artworks, genre, estado, horas_total, logros_obt, logros_total, console_pc, igdb_id, first_year_played, description) VALUES ('Cuphead', '28/09/2017', 'Studio MDHR', 'co62ao.webp', 'D-1n15aIgsE', 'ec5tsfhl7wjabwjnsshs.webp', 'Shooter, Platform, Adventure, Indie, Arcade', 'Completado', 4, 26, 42, 'Steam', 9061, 2026, 'Cuphead es un clásico juego de acción del tipo «correr y disparar» que se centra principalmente en las batallas contra jefes. Inspirado en los dibujos animados de la década de 1930, los gráficos y el audio se han creado minuciosamente con las mismas técnicas de la época, es decir, animación tradicional en cel (¡dibujada y entintada a mano!), fondos en acuarela y grabaciones originales de jazz. Juega como Cuphead o Mugman (en modo individual o cooperativo) mientras recorres mundos extraños, consigues nuevas armas, aprendes poderosos supermovimientos y descubres secretos ocultos. Cuphead es pura acción, todo el tiempo. Sin pausas para recargar, sin regeneración de salud y sin vidas extra. Solo tú, tu ingenio y tus reflejos para superar cada desafío.');
INSERT INTO dates_played (game_id, year, fecha_inicio, fecha_final, horas) VALUES ((SELECT id FROM games WHERE title = 'Cuphead'), 2026, '15/03/2026', '16/03/2026', 4);